// // This module implements a 4-bit binary counter with a pseudorandom number generator using a 64-bit shift register. The counter outputs the most significant bit on each clock cycle and updates the shift register with the XOR of specific bits.
module top_module(
  input                clk,
  input                rst_n,
  output reg  [3:0]    Q
);reg [63:0] shift_reg;
  wire xor_out;

  assign xor_out = shift_reg[0] ^ shift_reg[5] ^ shift_reg[10] ^ shift_reg[27] ^ shift_reg[63];

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      shift_reg <= 64'b0;
      Q <= 4'b0;
    end
    else begin
      shift_reg <= {shift_reg[62:0], xor_out};
      Q <= shift_reg[3:0];
    end
  end

endmodule
